    self._recompute_taxes()
    if self.partner_id:
        self.message_post(
            body=_('Product taxes have been recomputed according to'
                   ' fiscal position %s.',
                   self.fiscal_position_id._get_html_link()
                   if self.fiscal_position_id else '')
