@api.returns('mail.message', lambda value: value.id)
def message_post(self, **kwargs):
    if self.env.context.get('mark_so_as_sent'):
        self.filtered(
            lambda o: o.state == 'draft'
        ).with_context(tracking_disable=True).write({'state': 'sent'})
    so_ctx = {
        'mail_post_autofollow':
            self.env.context.get('mail_post_autofollow', True)
    }
    return super(SaleOrder, self.with_context(**so_ctx)).message_post(**kwargs)

